// // This module implements a 4-bit barrel shifter capable of shifting data left by 0, 1, or 2 positions, and providing an option for right shifting. It takes a 4-bit input and a 2-bit shift amount to determine the number of positions to shift. If the shift amount is 00, the output remains the same as the input. For 01 and 10, it shifts left by 1 and 2 bits, respectively. For 11, it outputs the 2-bit left shifted value if the direction signal indicates left, or the original input for a right shift, maintaining the integrity of the bit positions during the operation.
module top_module(
    input [3:0] data_in,
    input [1:0] shift_amount,
    input direction_left,
    output reg [3:0] data_out
);reg [3:0] shift_reg [1:3];

always @(*) begin
    shift_reg[1] = data_in;
    shift_reg[2] = shift_reg[1] << 1;
    shift_reg[3] = shift_reg[2] << 1;

    if (shift_amount == 2'b00) begin
        data_out = data_in;
    end else if (shift_amount == 2'b01) begin
        data_out = shift_reg[2];
    end else if (shift_amount == 2'b10) begin
        data_out = shift_reg[3];
    end else if (shift_amount == 2'b11) begin
        data_out = direction_left ? shift_reg[3] : shift_reg[1];
    end
end

endmodule
